import toast from 'react-hot-toast';

const LOGO = 'data:image/png;base64,';
function useCounter(end, duration = 1600, delay = 0) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    const t = setTimeout(() => {
      const steps = 60;
      let cur = 0;
      const iv = setInterval(() => {
        cur += end / steps;
        if (cur >= end) { setVal(end); clearInterval(iv); }
        else setVal(parseFloat(cur.toFixed(1)));
      }, duration / steps);
      return () => clearInterval(iv);
    }, delay);
    return () => clearTimeout(t);
  }, [end, duration, delay]);
  return val;
}

function StatCard({ icon, label, target, suffix, change, color, delay }) {
  const val = useCounter(target, 1600, 900 + delay);
  const [hovered, setHovered] = useState(false);
  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        background: 'white', borderRadius: 10, padding: '10px 12px',
        minWidth: 72, boxShadow: hovered ? '0 8px 24px rgba(0,0,0,0.14)' : '0 2px 8px rgba(0,0,0,0.06)',
        transform: hovered ? 'translateY(-3px) scale(1.04)' : 'none',
        transition: 'all 0.3s cubic-bezier(.34,1.56,.64,1)', cursor: 'default',
        animation: `cardIn 0.6s cubic-bezier(.34,1.56,.64,1) ${(900 + delay) / 1000}s both`,
      }}>
      <div style={{ fontSize: 16, marginBottom: 2 }}>{icon}</div>
      <div style={{ fontSize: 10, color: '#888', fontWeight: 500 }}>{label}</div>
      <div style={{ fontSize: 14, fontWeight: 800, color: '#1a1a2e' }}>
        {val >= target ? target : val}{suffix}
      </div>
      <div style={{ fontSize: 10, color, fontWeight: 600 }}>↑ {change}</div>
    </div>
  );
}

function AnimatedBar({ height, color, delay }) {
  const [grown, setGrown] = useState(false);
  useEffect(() => {
    const t = setTimeout(() => setGrown(true), 1300 + delay);
    return () => clearTimeout(t);
  }, [delay]);
  return (
    <div style={{
      width: 14, height: grown ? height : 0,
      background: color, borderRadius: '3px 3px 0 0',
      transition: `height 0.8s cubic-bezier(.34,1.56,.64,1) ${delay}ms`,
      alignSelf: 'flex-end',
    }} />
  );
}

